#include <bits/stdc++.h>
using namespace std;
vector<int> son[105];
int n,q;
int dp[105][105],val[105][105],flag[105];
void dfs(int x){
	flag[x]=1;
	for(int i=0;i<son[x].size();i++)
    {
		int ny=son[x][i];
		if(flag[ny]==1)	continue;
		flag[ny]=1;
		dfs(ny);
		for(int j=q;j>=1;j--){
			for(int k=j-1;k>=0;k--){
				dp[x][j]=max(dp[x][j],val[x][ny]+dp[ny][k]+dp[x][j-k-1]);
			}
		}
	}
}

int main()
{
    cin>>n>>q;
    for(int i=1;i<n;i++)
    {
        int a,b,c;
        cin>>a>>b>>c;
        val[a][b]=c;
        val[b][a]=c;
		son[a].push_back(b);
		son[b].push_back(a);
    }
    dfs(1);
    cout<<dp[1][q];
    return 0;
}
